// CustomMetrics holds all our Prometheus metrics for per-user, per-request tracking
type CustomMetrics struct {
	requestsTotal    *prometheus.CounterVec
	requestDuration  *prometheus.HistogramVec
	requestsInFlight *prometheus.GaugeVec
	responseSize     *prometheus.SummaryVec
	errorsTotal      *prometheus.CounterVec
	userSessions     *prometheus.GaugeVec
	lastRequestTime  *prometheus.GaugeVec
}

// NewCustomMetrics creates and registers all custom metrics
func NewCustomMetrics(reg prometheus.Registerer) *CustomMetrics {
	m := &CustomMetrics{
		requestsTotal: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Name: "app_requests_total",
				Help: "Total number of requests processed, partitioned by user, method, endpoint, and status.",
			},
			[]string{"user_id", "method", "endpoint", "status_code", "user_agent", "region"},
		),
		requestDuration: prometheus.NewHistogramVec(
			prometheus.HistogramOpts{
				Name:    "app_request_duration_seconds",
				Help:    "Duration of request processing in seconds, partitioned by user and endpoint.",
				Buckets: prometheus.DefBuckets,
			},
			[]string{"user_id", "method", "endpoint", "status_code", "region"},
		),
		requestsInFlight: prometheus.NewGaugeVec(
			prometheus.GaugeOpts{
				Name: "app_requests_in_flight",
				Help: "Number of requests currently being processed, partitioned by user and endpoint.",
			},
			[]string{"user_id", "endpoint"},
		),
		responseSize: prometheus.NewSummaryVec(
			prometheus.SummaryOpts{
				Name:       "app_response_size_bytes",
				Help:       "Response size in bytes, partitioned by user and endpoint.",
				Objectives: map[float64]float64{0.5: 0.05, 0.9: 0.01, 0.99: 0.001},
			},
			[]string{"user_id", "endpoint", "content_type"},
		),
		errorsTotal: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Name: "app_errors_total",
				Help: "Total number of errors, partitioned by user, endpoint, and error type.",
			},
			[]string{"user_id", "endpoint", "error_type", "error_code"},
		),
		userSessions: prometheus.NewGaugeVec(
			prometheus.GaugeOpts{
				Name: "app_user_active_sessions",
				Help: "Number of active sessions per user.",
			},
			[]string{"user_id", "session_type", "device_type"},
		),
		lastRequestTime: prometheus.NewGaugeVec(
			prometheus.GaugeOpts{
				Name: "app_user_last_request_timestamp",
				Help: "Timestamp of the last request per user and endpoint.",
			},
			[]string{"user_id", "endpoint"},
		),
	}

	reg.MustRegister(
		m.requestsTotal,
		m.requestDuration,
		m.requestsInFlight,
		m.responseSize,
		m.errorsTotal,
		m.userSessions,
		m.lastRequestTime,
	)

	return m
}

// RequestContext holds user-provided values for metric labels
type RequestContext struct {
	UserID      string
	Method      string
	Endpoint    string
	StatusCode  string
	UserAgent   string
	Region      string
	ContentType string
	DeviceType  string
	SessionType string
}

// TrackRequest records metrics for a single request
func (m *CustomMetrics) TrackRequest(ctx RequestContext, duration time.Duration, responseSizeBytes float64) {
	m.requestsTotal.With(prometheus.Labels{
		"user_id":    ctx.UserID,
		"method":     ctx.Method,
		"endpoint":   ctx.Endpoint,
		"status_code": ctx.StatusCode,
		"user_agent": ctx.UserAgent,
		"region":     ctx.Region,
	}).Inc()

	m.requestDuration.With(prometheus.Labels{
		"user_id":    ctx.UserID,
		"method":     ctx.Method,
		"endpoint":   ctx.Endpoint,
		"status_code": ctx.StatusCode,
		"region":     ctx.Region,
	}).Observe(duration.Seconds())

	m.responseSize.With(prometheus.Labels{
		"user_id":      ctx.UserID,
		"endpoint":     ctx.Endpoint,
		"content_type": ctx.ContentType,
	}).Observe(responseSizeBytes)

	m.lastRequestTime.With(prometheus.Labels{
		"user_id":  ctx.UserID,
		"endpoint": ctx.Endpoint,
	}).SetToCurrentTime()
}

// TrackInFlight increments/decrements in-flight gauge
func (m *CustomMetrics) TrackInFlight(userID, endpoint string, delta float64) {
	m.requestsInFlight.With(prometheus.Labels{
		"user_id":  userID,
		"endpoint": endpoint,
	}).Add(delta)
}

// TrackError records an error metric
func (m *CustomMetrics) TrackError(userID, endpoint, errorType, errorCode string) {
	m.errorsTotal.With(prometheus.Labels{
		"user_id":    userID,
		"endpoint":   endpoint,
		"error_type": errorType,
		"error_code": errorCode,
	}).Inc()
}

// TrackSession updates active session count
func (m *CustomMetrics) TrackSession(userID, sessionType, deviceType string, delta float64) {
	m.userSessions.With(prometheus.Labels{
		"user_id":      userID,
		"session_type": sessionType,
		"device_type":  deviceType,
	}).Add(delta)
}

// instrumentedHandler wraps an HTTP handler with per-user, per-request metrics
func instrumentedHandler(metrics *CustomMetrics, endpoint string, handler http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		userID := r.Header.Get("X-User-ID")
		if userID == "" {
			userID = r.URL.Query().Get("user_id")
		}
		if userID == "" {
			userID = "anonymous"
		}

		region := r.Header.Get("X-Region")
		if region == "" {
			region = "unknown"
		}

		deviceType := r.Header.Get("X-Device-Type")
		if deviceType == "" {
			deviceType = "unknown"
		}

		metrics.TrackInFlight(userID, endpoint, 1)
		defer metrics.TrackInFlight(userID, endpoint, -1)

		start := time.Now()

		rw := &responseWriter{ResponseWriter: w, statusCode: http.StatusOK}
		handler(rw, r)

		duration := time.Since(start)

		ctx := RequestContext{
			UserID:      userID,
			Method:      r.Method,
			Endpoint:    endpoint,
			StatusCode:  fmt.Sprintf("%d", rw.statusCode),
			UserAgent:   truncateUserAgent(r.UserAgent()),
			Region:      region,
			ContentType: rw.Header().Get("Content-Type"),
			DeviceType:  deviceType,
		}

		metrics.TrackRequest(ctx, duration, float64(rw.bytesWritten))

		if rw.statusCode >= 400 {
			errorType := "client_error"
			if rw.statusCode >= 500 {
				errorType = "server_error"
			}
			metrics.TrackError(userID, endpoint, errorType, fmt.Sprintf("%d", rw.statusCode))
		}
	}
}

// responseWriter wraps http.ResponseWriter to capture status code and bytes written
type responseWriter struct {
	http.ResponseWriter
	statusCode   int
	bytesWritten int
}

func (rw *responseWriter) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}

func (rw *responseWriter) Write(b []byte) (int, error) {
	n, err := rw.ResponseWriter.Write(b)
	rw.bytesWritten += n
	return n, err
}

func truncateUserAgent(ua string) string {
	if len(ua) > 50 {
		return ua[:50]
	}
	if ua == "" {
		return "unknown"
	}
	return ua
}

