func makeLoginHandler(metrics *CustomMetrics) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		userID := r.Header.Get("X-User-ID")
		if userID == "" {
			userID = r.URL.Query().Get("user_id")
		}
		deviceType := r.Header.Get("X-Device-Type")
		if deviceType == "" {
			deviceType = "web"
		}

		if userID != "" && userID != "anonymous" {
			metrics.TrackSession(userID, "authenticated", deviceType, 1)
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		w.Write([]byte(fmt.Sprintf(`{"status": "logged_in", "user_id": "%s"}`, userID)))
	}
}

func makeLogoutHandler(metrics *CustomMetrics) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		userID := r.Header.Get("X-User-ID")
		if userID == "" {
			userID = r.URL.Query().Get("user_id")
		}
		deviceType := r.Header.Get("X-Device-Type")
		if deviceType == "" {
			deviceType = "web"
		}

		if userID != "" && userID != "anonymous" {
			metrics.TrackSession(userID, "authenticated", deviceType, -1)
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusOK)
		w.Write([]byte(fmt.Sprintf(`{"status": "logged_out", "user_id": "%s"}`, userID)))
	}
}

